  ('dietitian-moex-11374', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是常見的「寄生蟲（parasite）」侵入人體的途徑？ 經皮膚侵入  因吸血昆蟲叮咬侵入  以食物為媒介經口侵入  因呼吸由空氣經肺部侵入', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11375', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何者不是界面活性劑（洗潔劑）中添加的「助劑」？ 烷基苯磺酸鹽  矽酸鹽  聚磷酸鹽類  羧甲基纖維素', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11376', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列食品用塑膠材料耐熱性最好的是： 高密度聚乙烯（HDPE）  低密度聚乙烯（LDPE）  聚丙烯（PP）  聚苯乙烯（PS）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11377', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '琺瑯和陶瓷餐具其最常見的衛生問題是： 彩繪顏料中重金屬的溶出    矽酸鹽化合物引起食物中蛋白質的分解 致癌物氯乙烯的釋出    高溫加熱過程中產生環氧化合物', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11378', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關餐具殺菌處理的敘述，何者不正確？ 以攝氏一百度的沸水，煮沸一分鐘以上  以攝氏一百度的蒸氣，加熱二分鐘以上 以攝氏八十度以上的熱水，加熱二分鐘以上  以攝氏一百一十度的乾熱狀態下，加熱處理十分鐘以上', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11379', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列有關「感染型（infection）」食物中毒的敘述，何者不正確？ 活的致病性微生物與食物一起食入  致病性微生物會在消化道中生長繁殖 此類致病性微生物絕對不會擴散到消化道以外的器官  通常潛伏期較「毒素型（intoxication）」食物中毒長', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11380', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '儲存食品時，所謂的「temperature danger zone」是指何種溫度範圍？ 5℃至60℃  10℃至50℃  20℃至40℃  -18℃至0℃', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11381', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列何種食品中毒微生物會形成「孢子（spore）」？ Clostridium perfringens  Campylobactor jejuni  Vibrio vulnificus  Staphylococcus aureus', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11382', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關「scombrotoxin intoxication」的敘述，何者不正確？ 又稱為histamine poisoning    常因攝食不新鮮之魚肉而引起 histamine是因為細菌分解魚肉中的histidine而產生  可藉由烹煮去除histamine', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11383', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關食品物料「乾式儲存（dry storage）」，下列敘述何者不正確？ 儲存區之溫度最好在10-25℃之間  儲存區之相對溼度最好在50-60%之間 物料可直接置於地面存放    儲存倉庫不宜有窗戶', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "019192853fdc", "answer_pdf_sha1": "3763ec3c90be", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
